import{_ as a,o as e,c as r,ai as l}from"./chunks/framework.SowO7O0D.js";const p=JSON.parse('{"title":"第十二课：价值投资","description":"","frontmatter":{},"headers":[],"relativePath":"guide/12-value-investing.md","filePath":"guide/12-value-investing.md","lastUpdated":0}'),d={name:"guide/12-value-investing.md"};function i(o,t,n,h,s,c){return e(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="第十二课-价值投资" tabindex="-1">第十二课：价值投资 <a class="header-anchor" href="#第十二课-价值投资" aria-label="Permalink to “第十二课：价值投资”">​</a></h1><p>这一课介绍<strong>巴菲特</strong>的投资理念，这是被证明长期有效的投资方法。</p><h2 id="一、什么是价值投资" tabindex="-1">一、什么是价值投资？ <a class="header-anchor" href="#一、什么是价值投资" aria-label="Permalink to “一、什么是价值投资？”">​</a></h2><p><strong>核心理念</strong>：买的不是股票代码，而是公司的真实价值。</p><blockquote><p>好公司 + 好价格 = 值得买入</p></blockquote><p>价值投资者相信：<strong>股价最终会反映公司的真实价值</strong>，所以要做的就是在价格低于价值时买入，耐心等待。</p><h2 id="二、股神巴菲特的核心理念" tabindex="-1">二、股神巴菲特的核心理念 <a class="header-anchor" href="#二、股神巴菲特的核心理念" aria-label="Permalink to “二、股神巴菲特的核心理念”">​</a></h2><h3 id="_1-买股票就是买公司" tabindex="-1">1. 买股票就是买公司 <a class="header-anchor" href="#_1-买股票就是买公司" aria-label="Permalink to “1. 买股票就是买公司”">​</a></h3><p>股票不是一张炒来炒去的纸，而是公司的一部分。</p><blockquote><p>巴菲特从不关心股价的短期波动，他关心的是公司业务是否健康。</p></blockquote><h3 id="_2-在别人恐惧时贪婪-在别人贪婪时恐惧" tabindex="-1">2. 在别人恐惧时贪婪，在别人贪婪时恐惧 <a class="header-anchor" href="#_2-在别人恐惧时贪婪-在别人贪婪时恐惧" aria-label="Permalink to “2. 在别人恐惧时贪婪，在别人贪婪时恐惧”">​</a></h3><p>这是巴菲特最著名的一句话。</p><ul><li>市场大跌时 ≠ 应该抛售，而是寻找被低估的好公司</li><li>市场大涨时 ≠ 应该追高，而是检查是否有泡沫</li></ul><h3 id="_3-护城河理论" tabindex="-1">3. 护城河理论 <a class="header-anchor" href="#_3-护城河理论" aria-label="Permalink to “3. 护城河理论”">​</a></h3><p>好公司要有<strong>护城河</strong>（竞争优势），让竞争对手难以超越：</p><table tabindex="0"><thead><tr><th>护城河类型</th><th>例子</th></tr></thead><tbody><tr><td>无形资产（品牌/专利）</td><td>茅台的品牌</td></tr><tr><td>转换成本</td><td>微信/QQ，你换不掉</td></tr><tr><td>网络效应</td><td>淘宝，用户越多越值钱</td></tr><tr><td>成本优势</td><td>比亚迪的电动车成本控制</td></tr></tbody></table><h2 id="三、价值投资三步法" tabindex="-1">三、价值投资三步法 <a class="header-anchor" href="#三、价值投资三步法" aria-label="Permalink to “三、价值投资三步法”">​</a></h2><h3 id="第一步-找到好公司" tabindex="-1">第一步：找到好公司 <a class="header-anchor" href="#第一步-找到好公司" aria-label="Permalink to “第一步：找到好公司”">​</a></h3><p>什么样的公司是好公司？</p><ul><li><strong>好行业</strong>：需求稳定，不容易被颠覆</li><li><strong>好商业模式</strong>：能持续赚钱，现金流好</li><li><strong>好管理层</strong>：诚实、有能力</li></ul><h3 id="第二步-评估内在价值" tabindex="-1">第二步：评估内在价值 <a class="header-anchor" href="#第二步-评估内在价值" aria-label="Permalink to “第二步：评估内在价值”">​</a></h3><p>这家公司真实值多少钱？</p><p>方法包括：</p><ul><li>PE、PB等估值指标</li><li>DCF现金流折现（专业方法）</li><li>净资产附近买入（格雷厄姆方法）</li></ul><h3 id="第三步-等到好价格" tabindex="-1">第三步：等到好价格 <a class="header-anchor" href="#第三步-等到好价格" aria-label="Permalink to “第三步：等到好价格”">​</a></h3><p>好公司也要有好价格。</p><blockquote><p>茅台是好公司，但如果在PE=70倍时买入，可能好几年都不赚钱。</p></blockquote><p><strong>好价格信号</strong>：</p><ul><li>PE在历史低位</li><li>熊市整体下跌时</li><li>公司遇到短期困难但本质没坏</li></ul><h2 id="四、a股价值投资典范" tabindex="-1">四、A股价值投资典范 <a class="header-anchor" href="#四、a股价值投资典范" aria-label="Permalink to “四、A股价值投资典范”">​</a></h2><table tabindex="0"><thead><tr><th>公司</th><th>代码</th><th>护城河</th></tr></thead><tbody><tr><td>贵州茅台</td><td>600519</td><td>品牌+稀缺性</td></tr><tr><td>腾讯控股</td><td>0700.HK</td><td>社交+游戏+金融</td></tr><tr><td>招商银行</td><td>600036</td><td>零售银行龙头</td></tr><tr><td>长江电力</td><td>600900</td><td>水电低成本+稳定分红</td></tr><tr><td>片仔癀</td><td>600436</td><td>中药绝密配方</td></tr></tbody></table><h2 id="五、价值投资的难点" tabindex="-1">五、价值投资的难点 <a class="header-anchor" href="#五、价值投资的难点" aria-label="Permalink to “五、价值投资的难点”">​</a></h2><blockquote><p>⚠️ <strong>价值投资知易行难，主要挑战：</strong></p></blockquote><ol><li><strong>需要耐心</strong>：可能3-5年才见效，急用钱的人不适合</li><li><strong>需要研究能力</strong>：要能判断公司是否真的好</li><li><strong>需要逆向思维</strong>：大家都在卖的时候，你敢买吗？</li><li><strong>需要承受波动</strong>：即使买对了，短期也可能跌30%</li></ol><h2 id="思考题" tabindex="-1">思考题 <a class="header-anchor" href="#思考题" aria-label="Permalink to “思考题”">​</a></h2><blockquote><p>茅台股价现在1700元，PE约45倍。巴菲特会买吗？为什么？</p></blockquote><hr><p><strong>下一课预告</strong>：价值投资学完了，下一课学习<strong>行业轮动</strong>——理解A股的结构性机会。</p>',38)])])}const g=a(d,[["render",i]]);export{p as __pageData,g as default};
